module ring_counter(
    input       obf_clk   ,
    input       reset ,

    output reg  [3:0] out
);

    // 4-bit Ring Counter
    always @(posedge obf_clk or posedge reset) begin
        if (reset)
            out <= 4'b0001;
        else
            out <= {out[2:0], out[3]};
    end

endmodule
